"""
This module represents the checkers board.
"""

class Board:
    def __init__(self):
        self.grid = [[' ' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces in the starting position
        for row in [0, 2]:
            for col in range(1, 8, 2):
                self.grid[row][col] = 'R'
        for row in [7, 5]:
            for col in range(0, 8, 2):
                self.grid[row][col] = 'B'

    def print_board(self):
        for row in self.grid:
            print(' '.join(row))

    def is_valid_move(self, start, end):
        # Basic move validation
        if abs(start[0] - end[0]) != 1 or abs(start[1] - end[1]) != 1:
            return False
        if self.grid[start[0]][start[1]] == ' ' or self.grid[end[0]][end[1]] != ' ':
            return False
        return True

    def make_move(self, start, end):
        if not self.is_valid_move(start, end):
            raise ValueError("Invalid move")
        self.grid[start[0]][start[1]], self.grid[end[0]][end[1]] = ' ', self.grid[start[0]][start[1]]

class Piece:
    def __init__(self, color):
        self.color = color

class Player:
    def __init__(self, name, pieces):
        self.name = name
        self.pieces = pieces
```

#### `game_logic.py`
```python
"""
This module contains the game logic.
"""

from board import Board

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'Red'

    def switch_turn(self):
        if self.current_player == 'Red':
            self.current_player = 'Black'
        else:
            self.current_player = 'Red'

    def play_game(self):
        while True:
            self.board.print_board()
            print(f"{self.current_player}'s turn. Enter move (e.g., A1-A2): ")
            try:
                start, end = input().split('-')
                start = (8 - int(start[1]), ord(start[0]) - ord('A'))
                end = (8 - int(end[1]), ord(end[0]) - ord('A'))
                self.board.make_move(start, end)
                self.switch_turn()
            except Exception as e:
                print(f"Error: {e}")

if __name__ == "__main__":
    game = Game()
    game.play_game()
```

